from flask import Flask, request, jsonify, Response
from prometheus_client import Counter, Gauge, Histogram, generate_latest, CONTENT_TYPE_LATEST, CollectorRegistry, multiprocess, make_wsgi_app
import time
import os

app = Flask(__name__)

REQUEST_COUNT = Counter(
    "app_requests_total",
    "Total number of HTTP requests",
    ["method", "endpoint", "status_code"],
)

REQUEST_LATENCY = Histogram(
    "app_request_latency_seconds",
    "HTTP request latency in seconds",
    ["method", "endpoint"],
    buckets=(0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1.0, 2.5, 5.0, 10.0),
)

IN_PROGRESS_REQUESTS = Gauge(
    "app_inprogress_requests",
    "Number of requests currently being processed",
    ["endpoint"],
)

BUSINESS_EVENTS = Counter(
    "app_business_events_total",
    "Total business events processed",
    ["event_type"],
)

ACTIVE_USERS = Gauge(
    "app_active_users",
    "Current number of active users",
)

ORDER_VALUE = Histogram(
    "app_order_value_usd",
    "Distribution of order values in USD",
    buckets=(0, 10, 25, 50, 100, 250, 500, 1000, 2500, 5000),
)

ITEMS_IN_CART = Gauge(
    "app_items_in_cart",
    "Number of items currently in the cart",
)

@app.before_request
def before_request():
    request._start_time = time.time()
    endpoint = request.endpoint or "unknown"
    IN_PROGRESS_REQUESTS.labels(endpoint=endpoint).inc()

@app.after_request
def after_request(response):
    endpoint = request.endpoint or "unknown"
    method = request.method
    status_code = response.status_code
    elapsed = time.time() - getattr(request, "_start_time", time.time())

    REQUEST_COUNT.labels(method=method, endpoint=endpoint, status_code=status_code).inc()
    REQUEST_LATENCY.labels(method=method, endpoint=endpoint).observe(elapsed)
    IN_PROGRESS_REQUESTS.labels(endpoint=endpoint).dec()

    return response

@app.route("/")
def index():
    BUSINESS_EVENTS.labels(event_type="page_view").inc()
    ACTIVE_USERS.inc()
    return jsonify({"message": "Welcome to the Flask app with Prometheus metrics"})

@app.route("/health")
def health():
    BUSINESS_EVENTS.labels(event_type="health_check").inc()
    return jsonify({"status": "ok"})

@app.route("/purchase", methods=["POST"])
def purchase():
    payload = request.get_json(silent=True) or {}
    order_value = float(payload.get("order_value", 0))
    items = int(payload.get("items", 0))

    BUSINESS_EVENTS.labels(event_type="purchase").inc()
    ORDER_VALUE.observe(order_value)
    ITEMS_IN_CART.set(items)

    return jsonify({"status": "purchase recorded", "order_value": order_value, "items": items})

@app.route("/users/active", methods=["POST"])
def set_active_users():
    payload = request.get_json(silent=True) or {}
    count = int(payload.get("count", 0))
    ACTIVE_USERS.set(count)
    BUSINESS_EVENTS.labels(event_type="active_users_update").inc()
    return jsonify({"status": "active users updated", "count": count})

@app.route("/metrics")
def metrics():
    registry = CollectorRegistry()
    if "prometheus_multiproc_dir" in os.environ:
        multiprocess.MultiProcessCollector(registry)
    else:
        registry = None
    output = generate_latest(registry) if registry is not None else generate_latest()
    return Response(output, mimetype=CONTENT_TYPE_LATEST)

@app.errorhandler(404)
def not_found(error):
    REQUEST_COUNT.labels(method=request.method, endpoint="404", status_code=404).inc()
    return jsonify({"error": "not found"}), 404

